import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import { toggleWishlist } from '../services/api';
import { toast } from 'react-toastify';

const Stars = ({ rating }) => '★'.repeat(Math.round(rating || 0)) + '☆'.repeat(5 - Math.round(rating || 0));

const ProductCard = ({ product }) => {
  const { addItem } = useCart();
  const { user } = useAuth();
  const BACKEND_URL = "http://localhost:5000";

  const handleAddToCart = () => {
    addItem(product);
    toast.success('Added to cart!');
  };

  const handleWishlist = async () => {
    if (!user) return toast.info('Please login to save to wishlist');
    try {
      await toggleWishlist(product._id);
      toast.success('Wishlist updated!');
    } catch { toast.error('Failed to update wishlist'); }
  };
const getImageUrl = (imgData) => {
  // If no image data, return placeholder
  if (!imgData) {
    const placeholder = `https://via.placeholder.com/500?text=${encodeURIComponent(product.name || 'Product')}`;
    console.debug('ProductCard.getImageUrl - no imgData, placeholder', placeholder);
    return placeholder;
  }

  // Extract URL from string or object
  const imageUrl = typeof imgData === 'string' ? imgData : imgData?.url;
  if (!imageUrl) {
    const placeholder = `https://via.placeholder.com/500?text=${encodeURIComponent(product.name || 'Product')}`;
    console.debug('ProductCard.getImageUrl - imageUrl undefined, placeholder', { imgData, placeholder });
    return placeholder;
  }

  // Cloudinary/full URL
  if (imageUrl.startsWith('http')) {
    console.debug('ProductCard.getImageUrl - external url', imageUrl);
    return imageUrl;
  }

  // Local backend upload - ensure proper formatting
  const cleanPath = imageUrl.startsWith('/') ? imageUrl.substring(1) : imageUrl;
  const url = `${BACKEND_URL}/uploads/${cleanPath}`;
  console.debug('ProductCard.getImageUrl - local url', { imageUrl, cleanPath, url });
  return url;
};

const img = product.images && product.images.length > 0 ? getImageUrl(product.images[0]) : `https://via.placeholder.com/500?text=${encodeURIComponent(product.name || 'Product')}`;
  const price = product.discountPrice > 0 ? product.discountPrice : product.price;

  return (
    <div className="product-card">
      <div className="card-img-wrap">
        <Link to={`/products/${product._id}`}>
          <img src={img} alt={product.name} loading="lazy" />
        </Link>
        <button className="wishlist-btn" onClick={handleWishlist} title="Add to wishlist">♡</button>
        {product.discountPrice > 0 && (
          <span className="badge-sale">-{Math.round((1 - product.discountPrice / product.price) * 100)}%</span>
        )}
      </div>
      <div className="card-body">
        <p className="card-category">{product.category}</p>
        <Link to={`/products/${product._id}`}><h3 className="card-title">{product.name}</h3></Link>
        <div className="card-rating">
          <span className="stars"><Stars rating={product.rating} /></span>
          <span className="review-count">({product.numReviews || 0})</span>
        </div>
        <div className="card-price">
          <span className="price-current">PKR {price.toLocaleString()}</span>
          {product.discountPrice > 0 && <span className="price-original">PKR {product.price.toLocaleString()}</span>}
        </div>
        <button className="btn-add-cart" onClick={handleAddToCart} disabled={product.stock === 0}>
          {product.stock === 0 ? 'Out of Stock' : 'Add to Cart'}
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
